293	static void launch_dispatch_copy_epilogue(void* buffer, void* workspace,
294	                                          int* psum_num_recv_tokens_per_scaleup_rank,
295	                                          int* psum_num_recv_tokens_per_expert,
296	                                          void* recv_x, void* recv_sf,
297	                                          topk_idx_t* recv_topk_idx, float* recv_topk_weights,
298	                                          int* recv_src_metadata,
299	                                          int* channel_linked_list,
300	                                          int* num_unaligned_recv_tokens_per_expert,
301	                                          const int& num_recv_tokens, const int& num_max_tokens_per_rank,
302	                                          const int& num_hidden_bytes,
303	                                          const int& num_sf_packs, const int& recv_sf_token_stride, const int& recv_sf_hidden_stride,
304	                                          const int& num_experts, const int& num_topk, const int& expert_alignment,
