77	    int64_t agrs_buffer_offset = 0;
78	    int agrs_buffer_slot_idx = 0;
79	
80	public:
81	    ElasticBuffer(const int& rank_idx, const int& num_ranks,
82	                  const int64_t& nccl_comm, const symmetric::cpu_comm_t& cpu_comm,
83	                  const int64_t& num_buffer_bytes, const int64_t& num_cpu_buffer_bytes,
84	                  const bool& allow_hybrid_mode,
85	                  const bool& allow_multiple_reduction,
86	                  const bool& prefer_overlap_with_compute,
87	                  const int& sl_idx, const int& num_allocated_qps,
88	                  const int& num_cpu_timeout_secs, const int& num_gpu_timeout_secs,
89	                  const bool& explicitly_destroy):
90	        num_buffer_bytes(num_buffer_bytes),
91	        num_cpu_buffer_bytes(num_cpu_buffer_bytes),
92	        explicitly_destroy(explicitly_destroy),
93	        comm_stream(get_global_comm_stream()),
94	        allow_hybrid_mode(allow_hybrid_mode),
95	        allow_multiple_reduction(allow_multiple_reduction),
96	        prefer_overlap_with_compute(prefer_overlap_with_compute) {
97	        // Check buffer bytes alignment (2 MB)
98	        EP_HOST_ASSERT(num_buffer_bytes > 0 and num_buffer_bytes % symmetric::kNumAlignmentBytes == 0);
99	        EP_HOST_ASSERT(num_cpu_buffer_bytes >= 0 and num_cpu_buffer_bytes % symmetric::kNumAlignmentBytes == 0);
100	        EP_HOST_ASSERT(num_cpu_buffer_bytes <= num_buffer_bytes);
101	        num_gpu_buffer_bytes = num_buffer_bytes - num_cpu_buffer_bytes;
102	
103	        // Workspace is aligned to 2 MB so that it sits cleanly at the front of the GPU segment
104	        const auto num_workspace_bytes = math::align<int64_t>(
105	            layout::WorkspaceLayout::get_num_bytes(), symmetric::kNumAlignmentBytes);
106	
107	        // Create NCCL symmetric memory context
108	        // Symmetric memory layout: [[[Workspace] GPU buffer] CPU buffer]
109	        // sym.num_bytes = workspace + buffer, sym.num_cpu_bytes = CPU buffer
110	        const auto num_sym_bytes = num_workspace_bytes + num_buffer_bytes;
111	        this->nccl_context = std::make_shared<nccl::NCCLSymmetricMemoryContext>(
112	            nccl_comm, cpu_comm, num_ranks, rank_idx,
113	            num_sym_bytes, num_cpu_buffer_bytes,
114	            allow_hybrid_mode, sl_idx, num_allocated_qps);
115	
116	        // Verify the symmetric memory layout matches our expectations
117	        EP_HOST_ASSERT(num_workspace_bytes + num_gpu_buffer_bytes == nccl_context->num_gpu_bytes);
118	        EP_HOST_ASSERT(num_cpu_buffer_bytes == nccl_context->num_cpu_bytes);
119	
120	        // Timeout
121	        this->num_cpu_timeout_secs = num_cpu_timeout_secs;
122	        this->num_gpu_timeout_cycles = static_cast<int64_t>(num_gpu_timeout_secs);
123	        this->num_gpu_timeout_cycles *= jit::device_runtime->get_clock_rate();
124	
125	        // Assign workspaces and buffers
126	        workspace = this->nccl_context->mapped_window_ptr;
127	        workspace_layout_wo_expert = std::make_shared<layout::WorkspaceLayout>(
128	            workspace, nccl_context->num_scaleout_ranks, nccl_context->num_scaleup_ranks, 0);
129	        buffer = static_cast<uint8_t*>(workspace) + num_workspace_bytes;
130	        CUDA_RUNTIME_CHECK(cudaMemset(workspace, 0, num_workspace_bytes));
131	
132	        // Allocate host workspaces
133	        CUDA_RUNTIME_CHECK(cudaMallocHost(&host_workspace, layout::WorkspaceLayout::get_num_bytes(), cudaHostAllocMapped));
134	        CUDA_RUNTIME_CHECK(cudaHostGetDevicePointer(&mapped_host_workspace, host_workspace, 0));
135	        std::memset(host_workspace, 0, layout::WorkspaceLayout::get_num_bytes());
136	
137	        // We should call a barrier at the end
138	        // The barrier should be called by Python `dist.barrier`
139	        // NOTES: do not call our barrier, as the workspace is not ready yet
140	    }
