142	    ~ElasticBuffer() noexcept(false) {
143	        if (not explicitly_destroy)
144	            destroy();
145	
146	        if (not destroyed) {
147	            printf("`destroy()` is not called before DeepEP elastic buffer destruction, which can leak resources.\n");
148	            fflush(stdout);
149	        }
150	    }
