242	    std::function<std::tuple<torch::Tensor, std::optional<torch::Tensor>>()>
243	    engram_fetch(const torch::Tensor& indices, int num_qps, const bool& use_tma_aligned_col_major_sf) const {
244	        const auto use_fp8 = engram_sf.has_value();
245	        const auto fetched_dtype = use_fp8 ? torch::kFloat8_e4m3fn : torch::kBFloat16;
246	        const int elem_size = use_fp8 ? sizeof(__nv_fp8_e4m3) : sizeof(nv_bfloat16);
247	        const auto [num_tokens, num_entries_per_token] = get_shape<2>(indices);
248	        EP_HOST_ASSERT(indices.scalar_type() == torch::kInt);
249	        EP_HOST_ASSERT(indices.is_cuda() and indices.is_contiguous());
250	        EP_HOST_ASSERT(num_tokens * num_entries_per_token * engram_hidden * elem_size <= num_gpu_buffer_bytes);
251	
252	        // Calculate a QP count
253	        if (num_qps == 0)
254	            num_qps = nccl_context->num_allocated_qps;
255	
256	        // Return tensor from the raw buffer: each token's entries are concatenated along hidden
257	        EP_HOST_ASSERT(num_engram_entries > 0);
258	        const auto fetched = torch::from_blob(
259	            buffer,
260	            {num_tokens, engram_hidden * num_entries_per_token},
261	            torch::TensorOptions().dtype(fetched_dtype).device(torch::kCUDA)
262	        );
263	
264	        auto fetched_sf = std::optional<torch::Tensor>();
265	        void* sf_table_ptr = nullptr;
266	        void* fetched_sf_ptr = nullptr;
267	        int num_sf_packs = 0, sf_token_stride = 0, sf_hidden_stride = 0;
268	        if (use_fp8) {
269	            num_sf_packs = static_cast<int>(engram_sf->size(1));
270	            if (use_tma_aligned_col_major_sf) {
271	                // TMA-aligned column-major layout for the next GEMM input
272	                sf_token_stride = 1, sf_hidden_stride = math::align(num_tokens, kNumAlignedSFPacks);
273	            } else {
274	                sf_token_stride = num_entries_per_token * num_sf_packs, sf_hidden_stride = 1;
275	            }
276	            fetched_sf = torch::empty_strided({num_tokens, num_entries_per_token * num_sf_packs},
277	                                              {sf_token_stride, sf_hidden_stride}, engram_sf->options());
278	            sf_table_ptr = engram_sf->data_ptr();
279	            fetched_sf_ptr = fetched_sf->data_ptr();
280	        }
281	
282	        // Last issued Gin requests
283	        const auto num_gin_ranks = allow_hybrid_mode
284	            ? nccl_context->num_scaleout_ranks
285	            : nccl_context->num_ranks;
286	        const auto last_gin_requests = torch::empty(
287	            {num_gin_ranks * num_qps, sizeof(ncclGinRequest_t)},
288	            torch::TensorOptions().dtype(torch::kByte).device(torch::kCUDA)
289	        );
290	
291	        // Launch the fetch kernel
292	        launch_engram_fetch(
293	            nccl_context->dev_comm, nccl_context->window,
294	            math::advance_ptr(buffer, num_gpu_buffer_bytes),
295	            fetched.data_ptr(),
296	            indices.data_ptr<int>(),
297	            static_cast<ncclGinRequest_t*>(last_gin_requests.data_ptr()),
298	            sf_table_ptr, fetched_sf_ptr, sf_token_stride, sf_hidden_stride,
299	            num_engram_entries,
300	            engram_hidden, elem_size, num_sf_packs,
301	            num_entries_per_token,
302	            num_tokens,
303	            nccl_context->num_scaleout_ranks,
304	            nccl_context->num_scaleup_ranks,
305	            num_cpu_buffer_bytes,
306	            num_qps,
307	            allow_hybrid_mode,
308	            at::cuda::getCurrentCUDAStream()
309	        );
310	
311	        return [=, this]() -> std::tuple<torch::Tensor, std::optional<torch::Tensor>> {
312	            // Wait for all RDMA gets to complete
313	            launch_engram_fetch_wait(
314	                static_cast<ncclGinRequest_t*>(last_gin_requests.data_ptr()),
315	                nccl_context->dev_comm,
316	                nccl_context->window,
317	                nccl_context->num_scaleout_ranks,
318	                nccl_context->num_scaleup_ranks,
319	                num_qps,
320	                allow_hybrid_mode,
321	                at::cuda::getCurrentCUDAStream()
322	            );
323	            return {fetched, fetched_sf};
324	        };
325	    }
