391	    void create_agrs_session() {
392	        EP_HOST_ASSERT(not agrs_in_session);
393	        agrs_in_session = true;
394	        agrs_buffer_offset = 0;
395	        agrs_buffer_slot_idx = 0;
396	        agrs_session_idx += 1;
