420	    std::vector<torch::Tensor> agrs_get_inplace_tensor(const std::vector<int64_t>& num_bytes_list) const {
421	        EP_HOST_ASSERT(num_bytes_list.size() >= 1);
422	        EP_HOST_ASSERT(num_max_agrs_session_bytes > 0 and num_max_agrs_per_session > 0 and agrs_in_session);
423	
424	        std::vector<torch::Tensor> out;
425	        out.reserve(num_bytes_list.size());
426	        int64_t offset = agrs_buffer_offset;
427	        for (const auto& num_bytes: num_bytes_list) {
428	            EP_HOST_ASSERT(offset + num_bytes * nccl_context->num_ranks <= num_max_agrs_session_bytes and
429	                           agrs_buffer_slot_idx < num_max_agrs_per_session and
430	                           "Not enough session buffer size. Did you forget to flush session?");
431	            out.push_back(torch::from_blob(math::advance_ptr(buffer, offset + num_bytes * nccl_context->rank_idx),
432	                          {num_bytes}, torch::TensorOptions().dtype(torch::kByte).device(torch::kCUDA)));
433	            offset += math::align<int64_t>(num_bytes * nccl_context->num_ranks, 32);
434	        }
435	        return out;
436	    }
