586	    static int64_t get_dispatch_buffer_size(const int& num_max_tokens_per_rank,
587	                                            const int& hidden, const int& num_sf_packs, const int& num_topk,
588	                                            const int& elem_size,
589	                                            const int& num_scaleout_ranks, const int& num_scaleup_ranks,
590	                                            const bool& is_scaleup_nvlink) {
591	        const auto num_ranks = num_scaleup_ranks * num_scaleout_ranks;
592	        const auto token_layout = get_dispatch_token_layout(hidden, elem_size, num_sf_packs, num_topk);
593	
594	        if (num_scaleout_ranks == 1) {
595	            // Direct dispatch
596	            const auto send_buffer_layout = layout::BufferLayout<false>(
597	                token_layout, is_scaleup_nvlink ? 0 : 1, num_max_tokens_per_rank);
598	            const auto recv_buffer_layout = layout::BufferLayout<false>(
599	                token_layout, num_ranks, num_max_tokens_per_rank);
600	            return send_buffer_layout.get_num_bytes() + recv_buffer_layout.get_num_bytes();
601	        } else {
602	            // Hybrid dispatch
603	            const auto scaleup_recv_buffer = layout::BufferLayout<false>(
604	                token_layout, num_scaleup_ranks, num_scaleout_ranks * num_max_tokens_per_rank);
605	            const auto scaleout_send_buffer = layout::BufferLayout<false>(
606	                token_layout, 1, num_max_tokens_per_rank);
607	            const auto scaleout_recv_buffer = layout::BufferLayout<false>(
608	                token_layout, num_scaleout_ranks,
609	                /* kNumChannels * kNumMaxTokensPerChannel */ num_max_tokens_per_rank + kNumMaxChannels);
610	            return scaleup_recv_buffer.get_num_bytes() +
611	                   scaleout_send_buffer.get_num_bytes() +
612	                   scaleout_recv_buffer.get_num_bytes();
613	        }
614	    }
615	
616	    static int64_t get_combine_buffer_size(const int& num_max_tokens_per_rank, const int& hidden, const int& num_topk,
617	                                           const int& num_scaleout_ranks, const int& num_scaleup_ranks,
618	                                           const bool& is_scaleup_nvlink,
619	                                           const bool& allow_multiple_reduction) {
620	        const auto num_ranks = num_scaleup_ranks * num_scaleout_ranks;
621	        const auto token_layout = get_combine_token_layout(hidden, sizeof(nv_bfloat16), num_topk);
622	
623	        if (num_scaleout_ranks == 1) {
624	            // Direct combine
625	            const auto num_tokens_in_layout = allow_multiple_reduction ? std::min(num_ranks, num_topk) : num_topk;
626	            const auto send_buffer_layout = layout::BufferLayout<false>(
627	                token_layout, is_scaleup_nvlink ? 0 : num_ranks,
628	                // For single reduction cases, the maximum number of received tokens is
629	                // `num_ranks * num_topk * num_max_tokens_per_rank` (we assume the bad case of `do_expand=True`)
630	                num_max_tokens_per_rank * (allow_multiple_reduction ? 1 : num_topk));
631	            const auto recv_buffer_layout = layout::BufferLayout<false>(
632	                token_layout, num_tokens_in_layout, num_max_tokens_per_rank);
633	            return send_buffer_layout.get_num_bytes() + recv_buffer_layout.get_num_bytes();
634	        } else {
635	            // Hybrid combine
636	            const int num_tokens_in_scaleup_layout = allow_multiple_reduction ? std::min(num_scaleup_ranks, num_topk) : num_topk;
637	            const int num_tokens_in_scaleout_layout = allow_multiple_reduction ? std::min(num_scaleout_ranks, num_topk) : num_topk;
638	            const auto scaleup_recv_buffer = layout::BufferLayout<false>(
639	                token_layout, num_tokens_in_scaleup_layout, num_scaleout_ranks * num_max_tokens_per_rank);
640	            const auto scaleout_recv_buffer = layout::BufferLayout<false>(
641	                token_layout, num_tokens_in_scaleout_layout, num_max_tokens_per_rank);
642	            const auto scaleout_send_buffer = layout::BufferLayout<false>(
643	                token_layout, allow_multiple_reduction ? 1 : num_topk,
644	                /* kNumChannels * num_scaleout_ranks * kNumMaxTokensPerChannel */
645	                num_scaleout_ranks * (num_max_tokens_per_rank + kNumMaxChannels));
646	            return scaleup_recv_buffer.get_num_bytes() +
647	                   scaleout_send_buffer.get_num_bytes() +
648	                   scaleout_recv_buffer.get_num_bytes();
649	        }
650	    }
651	
652	    static int64_t calculate_buffer_size(const int64_t& nccl_comm,
653	                                         const int& num_max_tokens_per_rank, const int& hidden,
654	                                         int num_topk, const bool& use_fp8_dispatch,
655	                                         const bool& allow_hybrid_mode,
656	                                         const bool& allow_multiple_reduction) {
657	        EP_HOST_ASSERT(num_max_tokens_per_rank > 0 and hidden > 0);
658	
659	        // The worst case SF bytes must be less than the main part
660	        EP_HOST_ASSERT(math::ceil_div(hidden, 32) * sizeof(float) <= hidden);
661	
662	        // NOTES: there are lots of `kNumTopk <= 32` restrictions, so we use 32 to calculate token size
663	        num_topk = num_topk == 0 ? 32 : num_topk;
664	
665	        // Topology
666	        const auto [num_rdma_ranks, num_nvl_ranks] = nccl::get_physical_domain_size(nccl_comm);
667	        const auto [num_scaleout_ranks, num_scaleup_ranks] = nccl::get_logical_domain_size(nccl_comm, allow_hybrid_mode);
668	        const auto is_scaleup_nvlink = num_scaleup_ranks == num_nvl_ranks;
669	
670	        // Dispatch size
671	        const auto elem_size = use_fp8_dispatch ? sizeof(__nv_fp8_e4m3) : sizeof(nv_bfloat16);
672	        const auto num_sf_packs = use_fp8_dispatch ? math::ceil_div(hidden, 32) : 0; // An approximation for number of SF packs
673	        const auto num_dispatch_bytes = get_dispatch_buffer_size(
674	            num_max_tokens_per_rank, hidden, num_sf_packs, num_topk, elem_size,
675	            num_scaleout_ranks, num_scaleup_ranks,
676	            is_scaleup_nvlink);
677	
678	        // Combine layout
679	        const auto num_combine_bytes = get_combine_buffer_size(
680	            num_max_tokens_per_rank, hidden, num_topk,
681	            num_scaleout_ranks, num_scaleup_ranks,
682	            is_scaleup_nvlink, allow_multiple_reduction);
683	
684	        // Return the maximum of those layouts, aligned to 2 MB
685	        return math::align(std::max(num_dispatch_bytes, num_combine_bytes), symmetric::kNumAlignmentBytes);
686	    }
