697	               std::vector<int>,
698	               torch::Tensor, torch::Tensor, torch::Tensor,
699	               torch::Tensor, torch::Tensor,
700	               std::optional<torch::Tensor>, std::optional<torch::Tensor>,
701	               std::optional<EventHandle>>
702	    dispatch(const torch::Tensor& x,
703	             const std::optional<torch::Tensor>& sf,
704	             const torch::Tensor& topk_idx,
705	             const std::optional<torch::Tensor>& topk_weights,
706	             const std::optional<torch::Tensor>& cumulative_local_expert_recv_stats,
707	             const std::optional<int>& cached_num_recv_tokens,
708	             const std::optional<int>& cached_num_expanded_tokens,
709	             const std::optional<std::vector<int>>& cached_num_recv_tokens_per_expert_list,
710	             const std::optional<torch::Tensor>& cached_psum_num_recv_tokens_per_scaleup_rank,
711	             const std::optional<torch::Tensor>& cached_psum_num_recv_tokens_per_expert,
712	             const std::optional<torch::Tensor>& cached_num_unaligned_recv_tokens_per_expert,
713	             const std::optional<torch::Tensor>& cached_dst_buffer_slot_idx,
714	             const std::optional<torch::Tensor>& cached_token_metadata_at_forward,
715	             const std::optional<torch::Tensor>& cached_recv_src_metadata,
716	             const std::optional<torch::Tensor>& cached_channel_linked_list,
717	             const int& num_max_tokens_per_rank,
718	             const int& num_experts, const int& expert_alignment,
719	             const int& num_sms, const int& num_qps,
720	             const std::optional<EventHandle>& previous_event,
721	             const std::optional<EventHandle>& previous_event_before_epilogue,
722	             const bool& async_with_compute_stream,
723	             const bool& allocate_on_comm_stream,
724	             const bool& do_handle_copy, const bool& do_cpu_sync,
725	             const bool& do_expand, const bool& do_zero_padding,
726	             const bool& use_tma_aligned_col_major_sf) const {
727	        // Check SM count
728	        EP_HOST_ASSERT(num_sms > 0);
729	
730	        // Zero padding only makes sense with expand mode
731	        EP_HOST_ASSERT(not do_zero_padding or do_expand);
732	
733	        // Cached mode must have responding handles
734	        const bool cached_mode = cached_num_recv_tokens.has_value();
735	        if (cached_mode) {
736	            EP_HOST_ASSERT(cached_num_recv_tokens.has_value());
737	            EP_HOST_ASSERT(cached_num_recv_tokens_per_expert_list.has_value());
738	            EP_HOST_ASSERT(cached_num_expanded_tokens.has_value());
739	            EP_HOST_ASSERT(cached_psum_num_recv_tokens_per_scaleup_rank.has_value());
740	            EP_HOST_ASSERT(cached_psum_num_recv_tokens_per_expert.has_value());
741	            EP_HOST_ASSERT(cached_dst_buffer_slot_idx.has_value());
742	
743	            // Hybrid kernels require more
744	            if (nccl_context->num_scaleout_ranks > 1) {
745	                EP_HOST_ASSERT(cached_token_metadata_at_forward.has_value());
746	                EP_HOST_ASSERT(cached_channel_linked_list.has_value());
747	            }
748	        }
749	
750	        // Check data tensor
751	        const auto [num_tokens, hidden] = get_shape<2>(x);
752	        const auto num_hidden_bytes = hidden * static_cast<int>(x.element_size());
753	        const auto num_local_experts = num_experts / nccl_context->num_ranks;
754	        EP_HOST_ASSERT(x.is_cuda() and x.is_contiguous());
755	        EP_HOST_ASSERT((x.size(1) * x.element_size()) % sizeof(int4) == 0);
756	        EP_HOST_ASSERT(num_tokens <= num_max_tokens_per_rank);
757	
758	        // Check SF stuffs
759	        int num_sf_packs = 0;
760	        void* sf_ptr = nullptr;
761	        int sf_token_stride = 0, sf_hidden_stride = 0;
762	        if (sf.has_value()) {
763	            // SF must be FP32 or packed UE8M0x4
764	            const auto [num_tokens_, num_sf_packs_] = get_shape<2>(sf.value());
765	            EP_HOST_ASSERT(num_tokens == num_tokens_);
766	            EP_HOST_ASSERT(sf->is_cuda());
767	            EP_HOST_ASSERT(sf->element_size() == sizeof(sf_pack_t));
768	            num_sf_packs = num_sf_packs_;
769	            sf_ptr = sf->data_ptr();
770	            sf_token_stride = sf->stride(0);
771	            sf_hidden_stride = sf->stride(1);
772	        }
773	
774	        // Check top-k stuffs
775	        const auto [num_tokens_, num_topk] = get_shape<2>(topk_idx);
776	        EP_HOST_ASSERT(num_tokens == num_tokens_);
777	        EP_HOST_ASSERT(topk_idx.scalar_type() == c10::CppTypeToScalarType<topk_idx_t>::value);
778	        EP_HOST_ASSERT(topk_idx.is_cuda() and topk_idx.is_contiguous());
779	
780	        // Weights are optional for training backward
781	        float* topk_weights_ptr = nullptr;
782	        if (topk_weights.has_value()) {
783	            const auto [num_tokens__, num_topk_] = get_shape<2>(topk_weights.value());
784	            EP_HOST_ASSERT(num_tokens == num_tokens__);
785	            EP_HOST_ASSERT(topk_weights->is_cuda() and topk_weights->is_contiguous());
786	            topk_weights_ptr = topk_weights->data_ptr<float>();
787	        }
788	
789	        // Expert receiving counter
790	        int* cumulative_local_expert_recv_stats_ptr = nullptr;
791	        if (cumulative_local_expert_recv_stats.has_value()) {
792	            const auto [num_local_experts_] = get_shape<1>(cumulative_local_expert_recv_stats.value());
793	            EP_HOST_ASSERT(cumulative_local_expert_recv_stats->is_cuda() and
794	                           cumulative_local_expert_recv_stats->is_contiguous());
795	            EP_HOST_ASSERT(num_local_experts == num_local_experts_);
796	            cumulative_local_expert_recv_stats_ptr = cumulative_local_expert_recv_stats->data_ptr<int>();
797	        }
798	
799	        // Stream control
800	        // All new tensor allocations should happen after this
801	        const auto compute_stream = stream_control_prologue(previous_event, allocate_on_comm_stream, async_with_compute_stream);
802	
803	        // The number of received tokens per expert
804	        // This is useful for expanding mode
805	        EP_HOST_ASSERT(num_experts % nccl_context->num_ranks == 0);
806	        auto psum_num_recv_tokens_per_expert = cached_psum_num_recv_tokens_per_expert.value_or(torch::Tensor());
807	        if (cached_mode) {
808	            const auto& [num_local_experts_] = get_shape<1>(psum_num_recv_tokens_per_expert);
809	            EP_HOST_ASSERT(num_local_experts == num_local_experts_);
810	            EP_HOST_ASSERT(psum_num_recv_tokens_per_expert.is_cuda() and psum_num_recv_tokens_per_expert.is_contiguous());
811	            EP_HOST_ASSERT(psum_num_recv_tokens_per_expert.scalar_type() == torch::kInt);
812	        } else {
813	            // NOTES: for expand mode, the input is exclusive prefix sum, while for non-expand, it is inclusive
814	            psum_num_recv_tokens_per_expert = torch::empty(
815	                {num_local_experts + 1}, at::TensorOptions(torch::kCUDA).dtype(torch::kInt));
816	        }
817	
818	        // The unaligned (actual) number of received tokens per expert
819	        // Written by the dispatch kernel's notify warps, used by the epilogue for zero padding
820	        auto num_unaligned_recv_tokens_per_expert = cached_num_unaligned_recv_tokens_per_expert.value_or(torch::Tensor());
821	        int* num_unaligned_recv_tokens_per_expert_ptr = nullptr;
822	        if (cached_mode) {
823	            const auto& [num_local_experts_] = get_shape<1>(num_unaligned_recv_tokens_per_expert);
824	            EP_HOST_ASSERT(num_local_experts == num_local_experts_);
825	            EP_HOST_ASSERT(num_unaligned_recv_tokens_per_expert.is_cuda() and num_unaligned_recv_tokens_per_expert.is_contiguous());
826	            EP_HOST_ASSERT(num_unaligned_recv_tokens_per_expert.scalar_type() == torch::kInt);
827	        } else {
828	            num_unaligned_recv_tokens_per_expert = torch::empty(
829	                {num_local_experts}, at::TensorOptions(torch::kCUDA).dtype(torch::kInt));
830	        }
831	        num_unaligned_recv_tokens_per_expert_ptr = num_unaligned_recv_tokens_per_expert.data_ptr<int>();
832	
833	        // The prefix sum tensor of number of received tokens from each rank
834	        // Will also be used in combine as the dispatch handle
835	        auto psum_num_recv_tokens_per_scaleup_rank = cached_psum_num_recv_tokens_per_scaleup_rank.value_or(torch::Tensor());
836	        if (cached_mode) {
837	            const auto [num_scaleup_ranks] = get_shape<1>(psum_num_recv_tokens_per_scaleup_rank);
838	            EP_HOST_ASSERT(num_scaleup_ranks == nccl_context->num_scaleup_ranks);
839	            EP_HOST_ASSERT(psum_num_recv_tokens_per_scaleup_rank.is_cuda() and psum_num_recv_tokens_per_scaleup_rank.is_contiguous());
840	            EP_HOST_ASSERT(psum_num_recv_tokens_per_scaleup_rank.scalar_type() == torch::kInt);
841	        } else {
842	            psum_num_recv_tokens_per_scaleup_rank = torch::empty(
843	                {nccl_context->num_scaleup_ranks}, at::TensorOptions(torch::kCUDA).dtype(torch::kInt));
844	        }
845	
846	        // Decide number of channels by shared memory consumption
847	        // Only for hybrid version
848	        int num_channels_per_sm = 1, num_channels = 1;
849	        const int num_smem_bytes = jit::device_runtime->get_num_smem_bytes();
850	        if (nccl_context->num_scaleout_ranks > 1) {
851	            const auto dispatch_token_layout = get_dispatch_token_layout(hidden, x.element_size(), num_sf_packs, num_topk);
852	            const auto combine_token_layout = get_combine_token_layout(hidden, sizeof(nv_bfloat16), num_topk);
853	            EP_HOST_ASSERT(num_sms <= kNumMaxSMs);
854	            num_channels_per_sm = std::min<int>(
855	                (num_smem_bytes - get_num_notify_smem_bytes(nccl_context->num_ranks, num_experts)) / dispatch_token_layout.get_num_bytes<true>(),
856	                32 - kNumNotifyWarps);
857	            num_channels_per_sm = std::min<int>(
858	                num_smem_bytes / combine_token_layout.get_num_bytes<true>(),
859	                num_channels_per_sm);
860	            num_channels_per_sm = std::min<int>(
861	                /* 2 kinds of warps */ num_channels_per_sm / 2, kNumMaxChannelsPerSM);
862	            if (not prefer_overlap_with_compute)
863	                num_channels_per_sm = std::min<int>(num_channels_per_sm, 4);
864	            num_channels = num_sms * num_channels_per_sm;
865	            if (get_env<int>("EP_BUFFER_DEBUG"))
866	                printf("Elastic buffer uses %d channels per SM\n", num_channels_per_sm);
867	        }
868	
869	        // Non-hybrid mode handles
870	        auto dst_buffer_slot_idx = cached_dst_buffer_slot_idx.value_or(torch::Tensor());
871	        if (nccl_context->num_scaleout_ranks == 1) {
872	            if (cached_mode) {
873	                const auto [num_tokens__, num_topk_] = get_shape<2>(dst_buffer_slot_idx);
874	                EP_HOST_ASSERT(num_tokens == num_tokens__ and num_topk == num_topk_);
875	                EP_HOST_ASSERT(dst_buffer_slot_idx.is_cuda() and dst_buffer_slot_idx.is_contiguous());
876	                EP_HOST_ASSERT(dst_buffer_slot_idx.scalar_type() == torch::kInt);
877	            } else {
878	                // Allocate a new tensor
879	                dst_buffer_slot_idx = torch::empty(
880	                    {num_tokens, num_topk}, torch::TensorOptions(torch::kCUDA).dtype(torch::kInt));
881	            }
882	        }
883	
884	        // Hybrid mode handles
885	        std::optional<torch::Tensor> token_metadata_at_forward, channel_linked_list;
886	        int *token_metadata_at_forward_ptr = nullptr, *channel_linked_list_ptr = nullptr;
887	        if (nccl_context->num_scaleout_ranks > 1) {
888	            // The token destination slot idx during forward
889	            // `[i, j, k, l]` means: from channel i from scale-out peer k, the j-th token's index in the l-th rank buffer
890	            // NOTES: Used primarily for cached mode
891	            // TODO: May make it a linked list to remove the redundant info in `token_metadata_at_forward`
892	            const auto num_max_tokens_per_channel = math::ceil_div(num_max_tokens_per_rank, num_channels);
893	            if (cached_mode) {
894	                const auto [num_channels_, num_scaleout_ranks_, num_max_tokens_per_channel_, num_topk_] =
895	                    get_shape<4>(dst_buffer_slot_idx);
896	                EP_HOST_ASSERT(num_channels == num_channels_ and nccl_context->num_scaleout_ranks == num_scaleout_ranks_ and
897	                               num_max_tokens_per_channel == num_max_tokens_per_channel_ and num_topk == num_topk_);
898	                EP_HOST_ASSERT(dst_buffer_slot_idx.is_cuda() and dst_buffer_slot_idx.is_contiguous());
899	                EP_HOST_ASSERT(dst_buffer_slot_idx.scalar_type() == torch::kInt);
900	            } else {
901	                dst_buffer_slot_idx = torch::empty(
902	                    {num_channels, nccl_context->num_scaleout_ranks, num_max_tokens_per_channel, num_topk},
903	                    torch::TensorOptions().device(torch::kCUDA).dtype(torch::kInt)
904	                );
905	            }
906	
907	            // The token metadata during forward
908	            // `[i, j]` means: in channel i, the j-th forwarded token's metadata
909	            // Info contains:
910	            //   - Scaleout rank index and source token index in the original rank (0)
911	            //   - Whether the token is the last one in the chunk (1)
912	            //   - cached top-k scaleup peer indices (top-k)
913	            //   - each selections' destination slot indices (top-k)
914	            const auto num_max_forwarded_tokens = nccl_context->num_scaleout_ranks * num_max_tokens_per_channel + 1;
915	            const auto num_forward_metadata_dims = 2 + num_topk * 2;
916	            if (cached_mode) {
917	                token_metadata_at_forward = cached_token_metadata_at_forward;
918	                const auto [num_channels_, num_max_forwarded_tokens_, num_forward_metadata_dims_] = get_shape<3>(token_metadata_at_forward.value());
919	                EP_HOST_ASSERT(num_channels == num_channels_ and num_max_forwarded_tokens == num_max_forwarded_tokens_
920	                               and num_forward_metadata_dims == num_forward_metadata_dims_);
921	                EP_HOST_ASSERT(token_metadata_at_forward->is_cuda() and token_metadata_at_forward->is_contiguous());
922	                EP_HOST_ASSERT(token_metadata_at_forward->scalar_type() == torch::kInt);
923	            } else {
924	                token_metadata_at_forward = torch::empty(
925	                    {num_channels, num_max_forwarded_tokens, num_forward_metadata_dims},
926	                    torch::TensorOptions().device(torch::kCUDA).dtype(torch::kInt)
927	                );
928	            }
929	            token_metadata_at_forward_ptr = token_metadata_at_forward->data_ptr<int>();
930	
931	            // Per-scaleup-peer-per-channel linked list
932	            // `[i, j, k]` means: from channel i from scaleup peer k, the j-th token's index in the combine's input
933	            if (cached_mode) {
934	                channel_linked_list = cached_channel_linked_list;
935	                const auto [num_channels__, d1_, d2_] = get_shape<3>(channel_linked_list.value());
936	                channel_linked_list_ptr = channel_linked_list->data_ptr<int>();
937	                EP_HOST_ASSERT(num_channels == num_channels__);
938	                EP_HOST_ASSERT(d1_ == nccl_context->num_scaleout_ranks * num_max_tokens_per_channel + 1);
939	                EP_HOST_ASSERT(d2_ == nccl_context->num_scaleup_ranks);
940	                EP_HOST_ASSERT(channel_linked_list->is_cuda() and channel_linked_list->is_contiguous());
941	                EP_HOST_ASSERT(channel_linked_list->scalar_type() == torch::kInt);
942	            } else {
943	                channel_linked_list = torch::empty(
944	                    // Index 0 of the list means the starting item
945	                    {num_channels,
946	                    nccl_context->num_scaleout_ranks * num_max_tokens_per_channel + 1,
947	                    nccl_context->num_scaleup_ranks},
948	                    torch::TensorOptions().device(torch::kCUDA).dtype(torch::kInt)
949	                );
950	            }
951	            channel_linked_list_ptr = channel_linked_list->data_ptr<int>();
952	        }
953	
954	        // Clone `topk_idx` for saving in the handle (to prevent users' modification)
955	        auto copied_topk_idx = std::optional<torch::Tensor>();
956	        topk_idx_t* copied_topk_idx_ptr = nullptr;
957	        if (do_handle_copy and not cached_mode) {
958	            copied_topk_idx = torch::empty_like(topk_idx);
959	            copied_topk_idx_ptr = copied_topk_idx->data_ptr<topk_idx_t>();
960	        }
961	
962	        // Check buffer size
963	        EP_HOST_ASSERT(get_dispatch_buffer_size(
964	                       num_max_tokens_per_rank, hidden, num_sf_packs, num_topk, x.element_size(),
965	                       nccl_context->num_scaleout_ranks, nccl_context->num_scaleup_ranks,
966	                       nccl_context->is_scaleup_nvlink) <= num_buffer_bytes);
967	
968	        // Ready and clean host workspace for this round
969	        const auto host_workspace_layout = layout::WorkspaceLayout(
970	            host_workspace,
971	            nccl_context->num_scaleout_ranks,
972	            nccl_context->num_scaleup_ranks,
973	            num_experts);
974	        std::fill_n(host_workspace_layout.get_scaleup_rank_count_ptr<false>(), nccl_context->num_scaleup_ranks, 0);
975	        std::fill_n(host_workspace_layout.get_scaleup_expert_count_ptr<false>(), num_local_experts, 0);
976	        std::atomic_thread_fence(std::memory_order_seq_cst);
977	
978	        // Do dispatch into the buffers (with SM limitation)
979	        EP_HOST_ASSERT(num_sms <= jit::device_runtime->get_num_sms());
980	        launch_dispatch(x.data_ptr(), sf_ptr,
981	                        topk_idx.data_ptr<topk_idx_t>(), topk_weights_ptr,
982	                        copied_topk_idx_ptr,
983	                        cumulative_local_expert_recv_stats_ptr,
984	                        psum_num_recv_tokens_per_scaleup_rank.data_ptr<int>(),
985	                        psum_num_recv_tokens_per_expert.data_ptr<int>(),
986	                        num_unaligned_recv_tokens_per_expert_ptr,
987	                        dst_buffer_slot_idx.data_ptr<int>(),
988	                        token_metadata_at_forward_ptr,
989	                        num_tokens, num_max_tokens_per_rank,
990	                        hidden, x.element_size(),
991	                        num_sf_packs, sf_token_stride, sf_hidden_stride,
992	                        num_experts, num_topk, expert_alignment,
993	                        nccl_context->dev_comm, nccl_context->window,
994	                        buffer,
995	                        workspace, mapped_host_workspace,
996	                        nccl_context->scaleout_rank_idx, nccl_context->scaleup_rank_idx,
997	                        nccl_context->num_scaleout_ranks, nccl_context->num_scaleup_ranks,
998	                        nccl_context->is_scaleup_nvlink,
999	                        num_sms, num_channels_per_sm,
1000	                        num_smem_bytes,
1001	                        num_qps, num_gpu_timeout_cycles,
1002	                        cached_mode, do_cpu_sync,
1003	                        comm_stream);
1004	
1005	        // Received token counters
1006	        int num_recv_tokens = 0, num_expanded_tokens = 0;
1007	        int counter_scaleup_rank_idx = 0, counter_local_expert_idx = 0;
1008	        std::vector<int> num_recv_tokens_per_expert_list;
1009	
1010	        // Assign these values according to modes
1011	        if (cached_mode) {
1012	            // Cached mode
1013	            EP_HOST_ASSERT(not do_cpu_sync and "Cannot do CPU sync with cached mode");
1014	            num_recv_tokens = cached_num_recv_tokens.value();
1015	            num_recv_tokens_per_expert_list = cached_num_recv_tokens_per_expert_list.value();
1016	            num_expanded_tokens = cached_num_expanded_tokens.value();
1017	        } else if (do_cpu_sync) {
1018	            // Non-cached mode with sync
1019	            const auto start_cpu_time = std::chrono::high_resolution_clock::now();
1020	            while (true) {
1021	                bool ready = true;
1022	
1023	                // Read number of received tokens from each scaleup rank
1024	                while (counter_scaleup_rank_idx < nccl_context->num_scaleup_ranks and ready) {
1025	                    const auto count = math::encode_decode_positive(
1026	                        host_workspace_layout.get_scaleup_rank_count_ptr<false>()[counter_scaleup_rank_idx]);
1027	                    if ((ready = math::is_decoded_positive_ready(count))) {
1028	                        num_recv_tokens += count;
1029	                        ++ counter_scaleup_rank_idx;
1030	                    }
1031	                }
1032	
1033	                // Read expert counts
1034	                while (counter_local_expert_idx < num_local_experts and ready) {
1035	                    const auto count = math::encode_decode_positive(
1036	                        host_workspace_layout.get_scaleup_expert_count_ptr<false>()[counter_local_expert_idx]);
1037	                    if ((ready = math::is_decoded_positive_ready(count))) {
1038	                        num_recv_tokens_per_expert_list.push_back(count);
1039	                        num_expanded_tokens += count;
1040	                        ++ counter_local_expert_idx;
1041	                    }
1042	                }
1043	
1044	                // Ready and do next steps
1045	                const auto get_buffer_info = [&]() {
1046	                    std::stringstream ss;
1047	                    ss << "CPU side received count (scaleup: " << nccl_context->scaleup_rank_idx << "): ";
1048	                    for (int i = 0; i < nccl_context->num_scaleup_ranks + num_local_experts; ++ i) {
1049	                        ss << host_workspace_layout.get_scaleup_rank_expert_count_ptr<false>()[i];
1050	                        ss << (i == nccl_context->num_scaleup_ranks - 1 ? " # ": " ");
1051	                    }
1052	                    return ss.str();
1053	                };
1054	                if (ready) {
1055	                    if (get_env<int>("EP_BUFFER_DEBUG"))
1056	                        printf("%s\n", get_buffer_info().c_str());
1057	                    break;
1058	                }
1059	
1060	                // Timeout checks
1061	                const auto now = std::chrono::high_resolution_clock::now();
1062	                if (std::chrono::duration_cast<std::chrono::seconds>(now - start_cpu_time).count() > num_cpu_timeout_secs)
