11	namespace deep_ep::elastic {
12	
13	template <bool kDoCPUSync,
14	          bool kReuseSlotIndices,
15	          int kNumSMs,
16	          int kNumNotifyWarps, int kNumScaleoutWarps, int kNumForwardWarps,
17	          int kNumScaleoutRanks, int kNumScaleupRanks,
18	          int kNumHiddenBytes, int kNumSFPacks,
19	          int kNumMaxTokensPerRank,
20	          int kNumExperts, int kNumTopk, int kExpertAlignment,
21	          int kNumQPs, int64_t kNumTimeoutCycles,
22	          int kNumScaleupRanksPerLane = math::constexpr_ceil_div(kNumScaleupRanks, 32),
23	          int kNumChannelsPerSM = kNumScaleoutWarps,
24	          int kNumChannels = kNumScaleoutWarps * kNumSMs,
25	          int kNumMaxTokensPerChannel = math::constexpr_ceil_div(kNumMaxTokensPerRank, kNumChannels),
26	          int kScaleoutUpdateInterval = 6,
27	          int kNumSlotsPerForwardChunk = kScaleoutUpdateInterval,
28	          int kNumRanks = kNumScaleoutRanks * kNumScaleupRanks,
29	          int kNumNotifyThreads = kNumNotifyWarps * 32,
30	          int kNumScaleoutSendThreads = kNumScaleoutWarps * 32,
31	          int kNumForwardThreads = kNumForwardWarps * 32,
32	          int kNumThreads = kNumNotifyThreads + kNumScaleoutSendThreads + kNumForwardThreads>
33	__global__ void __launch_bounds__(kNumThreads, 1)
34	hybrid_dispatch_impl(
35	    void* x, sf_pack_t* sf, topk_idx_t* topk_idx, float* topk_weights,
36	    topk_idx_t* copied_topk_idx,
37	    int* cumulative_local_expert_recv_stats,
38	    int* psum_num_recv_tokens_per_scaleup_rank,
39	    int* psum_num_recv_tokens_per_expert,
40	    int* num_unaligned_recv_tokens_per_expert,
41	    int* dst_buffer_slot_idx,
42	    int* token_metadata_at_forward,
43	    const int num_tokens,
44	    const int sf_token_stride, const int sf_hidden_stride,
45	    // TODO(NCCL): so many params, plans to optimize?
46	    const ncclDevComm_t nccl_dev_comm, const ncclWindow_t nccl_window,
47	    void* buffer,
48	    void* workspace, void* mapped_host_workspace,
49	    const int scaleout_rank_idx, const int scaleup_rank_idx) {
50	    constexpr int kNumExpertsPerRank = kNumExperts / kNumRanks;
51	    constexpr int kNumExpertsPerScaleout = kNumExperts / kNumScaleoutRanks;
52	    EP_STATIC_ASSERT(kNumExperts % kNumScaleupRanks == 0, "Invalid number of experts or ranks");
53	    EP_STATIC_ASSERT(kNumNotifyWarps % 4 == 0, "Invalid warpgroup size");
54	    EP_STATIC_ASSERT(kNumScaleoutWarps == kNumForwardWarps, "Invalid warp size");
55	
56	    // Utils
57	    // NOTES: a warp is a channel (different channels may share QPs)
58	    const auto sm_idx = static_cast<int>(blockIdx.x), thread_idx = static_cast<int>(threadIdx.x);
59	    const auto warp_idx = ptx::get_warp_idx(), lane_idx = ptx::get_lane_idx();
60	    const auto rank_idx = scaleout_rank_idx * kNumScaleupRanks + scaleup_rank_idx;
61	
62	    // Workspaces
63	    const auto workspace_layout = layout::WorkspaceLayout(workspace, kNumScaleoutRanks, kNumScaleupRanks, kNumExperts);
64	    const auto host_workspace_layout = layout::WorkspaceLayout(mapped_host_workspace, kNumScaleoutRanks, kNumScaleupRanks, kNumExperts);
65	
66	    // The kernel uses a fixed space of dynamic shared memory (no static shared memory)
67	    extern __shared__ __align__(ptx::kNumTMAAlignBytes) int8_t smem[];
68	    constexpr int kNumSmemBytesForNotify = kNumNotifyThreads > 0 ?
69	        math::constexpr_align(kNumRanks + kNumExperts, kNumNotifyThreads) * sizeof(int) : 0;
70	    EP_STATIC_ASSERT(kNumSmemBytesForNotify % ptx::kNumTMAAlignBytes == 0, "Invalid TMA alignment");
71	
72	    // Named barrier indices
73	    constexpr int kNotifyBarrierIndex = 1;
74	
75	    // NCCL Gin handle
76	    // Each warp is a channel
77	    const auto [qp_idx, sharing_mode] = comm::get_qp_mode<kNumSMs, kNumQPs, kNumChannelsPerSM, (kNumNotifyWarps > 0)>(
78	        sm_idx, (warp_idx - kNumNotifyWarps) % kNumChannelsPerSM, warp_idx < kNumNotifyWarps);
79	    const auto gin = handle::NCCLGin(nccl_dev_comm, nccl_window, qp_idx, sharing_mode);
80	
81	    // Global parallel barriers for scale-out subteam and scale-up subteam
82	    comm::gpu_barrier<true, kNumScaleoutRanks, kNumScaleupRanks,
83	                      kNumSMs, kNumThreads, kNumQPs, kNumTimeoutCycles, comm::kHybridDispatchTag0, false, false, true>(
84	        gin, workspace_layout, scaleout_rank_idx, scaleup_rank_idx, sm_idx, thread_idx);
85	
86	    // The golden layout during the whole process for both scale-out and forward warps
87	    const auto token_layout = layout::TokenLayout(kNumHiddenBytes, kNumSFPacks * sizeof(sf_pack_t), kNumTopk, true);
88	    const auto tma_buffer = layout::BufferLayout<true>(token_layout, kNumScaleoutWarps + kNumForwardWarps, 1,
89	            math::advance_ptr<int>(smem, kNumSmemBytesForNotify)).get_rank_buffer(warp_idx - kNumNotifyWarps).get_token_buffer(0);
90	
91	    // All the buffers
92	    auto scaleup_buffer = layout::BufferLayout<false>(
93	        token_layout, kNumScaleupRanks, kNumScaleoutRanks * kNumMaxTokensPerRank, buffer);
94	    auto scaleout_send_buffer = layout::BufferLayout<false>(
95	        token_layout, 1, kNumMaxTokensPerRank, scaleup_buffer.get_buffer_end_ptr());
96	    auto scaleout_recv_buffer = layout::BufferLayout<false>(
97	        token_layout, kNumScaleoutRanks, kNumChannels * kNumMaxTokensPerChannel, scaleout_send_buffer.get_buffer_end_ptr());
98	
99	    // Init TMA for scale-out and forward warps
100	    ptx::arrival_phase phase = 0;
101	    const auto mbarrier_ptr = tma_buffer.get_mbarrier_ptr();
102	    if (warp_idx >= kNumNotifyWarps and ptx::elect_one_sync())
103	        ptx::mbarrier_init_with_fence(mbarrier_ptr, 1);
104	    __syncwarp();
105	
106	    // Different warp roles
107	    if (warp_idx < kNumNotifyWarps) {
108	        // Assign shared memory
109	        constexpr int kNumAlignedElems = kNumSmemBytesForNotify / sizeof(int);
110	        const auto rank_expert_count = math::advance_ptr<int>(smem, 0);
111	
112	        // Clean initial counts
113	        // NOTES: if you want to change the order of different warp roles, please take care of the `thread_idx`
114	        int *rank_count = rank_expert_count, *expert_count = rank_expert_count + kNumRanks;
115	        #pragma unroll
116	        for (int i = 0; i < kNumAlignedElems / kNumNotifyThreads; ++ i)
117	            rank_expert_count[i * kNumNotifyThreads + thread_idx] = 0;
118	        ptx::named_barrier<kNumNotifyThreads>(kNotifyBarrierIndex);
119	
120	        // Atomic add on shared memory
121	        EP_STATIC_ASSERT(kNumTopk <= 32, "Insufficient lanes");
122	        const auto global_warp_idx = sm_idx * kNumNotifyWarps + warp_idx;
123	        for (int i = global_warp_idx; i < num_tokens; i += kNumNotifyWarps * kNumSMs) {
124	            // Expert choice can not be redundant
125	            // NOTES: no assertions here as they are expensive
126	            const auto dst_expert_idx = lane_idx < kNumTopk ?
127	                static_cast<int>(__ldg(topk_idx + i * kNumTopk + lane_idx)) : -1;
128	            if (dst_expert_idx >= 0)
129	                atomicAdd_block(expert_count + dst_expert_idx, 1);
130	
131	            // Rank choice should do deduplication here
132	            const auto dst_rank_idx = dst_expert_idx >= 0 ? dst_expert_idx / kNumExpertsPerRank : -1;
133	            if (ptx::deduplicate(dst_rank_idx, lane_idx) and dst_rank_idx >= 0)
134	                atomicAdd_block(rank_count + dst_rank_idx, 1);
135	        }
136	        ptx::named_barrier<kNumNotifyThreads>(kNotifyBarrierIndex);
137	
138	        // Do full-grid reduction
139	        #pragma unroll
140	        for (int i = thread_idx; i < kNumRanks + kNumExperts; i += kNumNotifyThreads) {
141	            const int64_t counter = (1ll << 32ll) | rank_expert_count[i];
142	            ptx::red_add(workspace_layout.get_notify_reduction_workspace_ptr() + i, counter);
143	        }
144	
145	        // Do the remaining work by SM 0
146	        if (sm_idx == 0) {
147	            // Reduce all SM's count
148	            // Wait all SMs' arrival
149	            #pragma unroll
150	            for (int i = thread_idx; i < kNumRanks + kNumExperts; i += kNumNotifyThreads) {
151	                comm::timeout_while<kNumTimeoutCycles>([=](const bool& is_last_check) {
152	                    const auto status = ptx::ld_volatile<int64_t>(workspace_layout.get_notify_reduction_workspace_ptr() + i);
153	                    if ((status >> 32) == kNumSMs) {
154	                        // Encode and write into the send buffer
155	                        workspace_layout.get_scaleout_rank_expert_count_ptr<true>()[i] =
156	                            math::encode_decode_positive<int>(status & 0xffffffffll);
157	
158	                        // Clean for the next usage
159	                        workspace_layout.get_notify_reduction_workspace_ptr()[i] = 0;
160	                        return true;
161	                    }
162	
163	                    if (is_last_check) {
164	                        printf("DeepEP hybrid notify (GPU reduction) timeout, scale-out: %d/%d, scale-up: %d/%d, "
165	                               "thread: %d, status: %d | %d, expected: %d\n",
166	                               scaleout_rank_idx, kNumScaleoutRanks, scaleup_rank_idx, kNumScaleupRanks, thread_idx,
