589	                }
590	                __syncwarp();
591	
592	                // Issue TMAs
593	                if (stored_dst_slot_idx >= 0) {
594	                    const auto dst_ptr = gin.get_sym_ptr<ncclTeamTagLsa>(
595	                        scaleup_buffer.get_token_buffer(stored_dst_slot_idx).get_base_ptr(),
596	                        stored_dst_scaleup_rank_idx);
597	                    ptx::tma_store_1d(dst_ptr, tma_buffer.get_base_ptr(), tma_buffer.get_num_bytes<false>());
598	                    ptx::tma_store_commit();
599	                }
600	                __syncwarp();
601	
602	                // Add per-scale-up counter
603	                EP_STATIC_ASSERT(kNumScaleupRanks <= 64, "Invalid number of scale-up peers");
604	                using mask_t = std::conditional_t<kNumScaleupRanks <= 32, unsigned, unsigned long long>;
605	                const auto scaleup_send_mask = ptx::reduce_or(
606	                    stored_dst_scaleup_rank_idx >= 0 ?
607	                    (mask_t(1) << stored_dst_scaleup_rank_idx) : mask_t(0));
608	                #pragma unroll
609	                for (int j = 0; j < kNumScaleupRanksPerLane; ++ j)
610	                    stored_scaleup_send_counters[j] += (scaleup_send_mask >> (j * 32 + lane_idx)) & 1;
611	
612	                // Record metadata at forward
613	                if constexpr (not kReuseSlotIndices) {
614	                    EP_STATIC_ASSERT(kNumTopk <= 32, "Invalid number of selections");
615	                    const auto metadata_ptr = token_metadata_at_forward +
616	                        num_tokens_processed * kNumForwardMetadataDims;
617	
618	                    // Source token index and last token index flag
619	                    if (ptx::elect_one_sync()) {
620	                        metadata_ptr[0] = tma_buffer.get_src_token_global_idx_ptr()[0];
621	                        metadata_ptr[1] = slot_idx == (end_slot_idx - 1);
622	                    }
623	
624	                    // Second, original top-k indices and destination slots
625	                    if (lane_idx < kNumTopk) {
626	                        metadata_ptr[2 + lane_idx] = stored_dst_scaleup_rank_idx;
627	                        metadata_ptr[2 + kNumTopk + lane_idx] = stored_dst_slot_idx;
628	                        dst_slot_idx_ptr[lane_idx] = stored_dst_slot_idx;
629	                    }
630	                }
631	                num_tokens_processed += 1;
632	                __syncwarp();
633	            }
634	        }
635	
636	        // Assign the source token index part of the metadata into `-1` as an ending mark
637	        if (not kReuseSlotIndices and ptx::elect_one_sync())
638	            token_metadata_at_forward[num_tokens_processed * kNumForwardMetadataDims] = -1;
639	        __syncwarp();
640	
641	        // Update linked list's ending position
642	        if constexpr (not kReuseSlotIndices) {
643	            const auto tail_ptr = workspace_layout.get_channel_scaleup_tail_ptr(channel_idx, scaleup_rank_idx);
644	            #pragma unroll
645	            for (int i = 0; i < kNumScaleupRanksPerLane; ++ i) {
646	                if (const auto j = i * 32 + lane_idx; i < (kNumScaleupRanksPerLane - 1) or j < kNumScaleupRanks) {
647	                    ptx::st_relaxed_sys(
648	                        gin.get_sym_ptr<ncclTeamTagLsa>(tail_ptr, j),
649	                        transform_linked_list_idx(stored_scaleup_send_counters[i]));
650	                }
651	            }
652	        }
653	        __syncwarp();
654	
655	        // Clean tails for next usages
656	        if (lane_idx < kNumScaleoutRanks)
657	            *workspace_layout.get_scaleout_channel_signaled_tail_ptr(channel_idx, lane_idx) = 0;
658	        __syncwarp();
659	    }
660	
661	    // Scale-up barrier to ensure data arrival
662	    // As scale-out tokens have already been consumed by forwarders, no need to do scale-out barrier again
663	    comm::gpu_barrier<true, kNumScaleoutRanks, kNumScaleupRanks,
664	                      kNumSMs, kNumThreads, kNumQPs, kNumTimeoutCycles, comm::kHybridDispatchTag1, true, true, false>(
665	        gin, workspace_layout, scaleout_rank_idx, scaleup_rank_idx, sm_idx, thread_idx, /* do not scale-out */ false, true);
666	
667	    // Trigger the copy epilogue kernel
668	    cudaTriggerProgrammaticLaunchCompletion();
669	
670	    // Clean scale-up counters
671	    // All scale-out counters should be cleaned before
672	    EP_STATIC_ASSERT(kNumScaleupRanks <= kNumThreads, "Insufficient threads");
673	    if (not kReuseSlotIndices and sm_idx == 0 and thread_idx < kNumScaleupRanks)
674	        workspace_layout.get_scaleup_atomic_sender_counter()[thread_idx] = 0;
675	}
676	
677	}  // namespace deep_ep::elastic
