30	template <int64_t kNumTimeoutCycles, typename func_t>
31	__device__ __forceinline__ void timeout_while(const bool& condition, const func_t& func,
32	                                              int64_t start_clock = 0) {
33	    // User may share a start clock for multiple waits
34	    if (start_clock == 0)
35	        start_clock = clock64();
36	
37	    while (condition) {
38	        const bool timeout = clock64() - start_clock >= kNumTimeoutCycles;
39	        if (func(timeout))
40	            break;
41	
42	        if (timeout) {
43	            // Wait another 1 second to let all threads print information and trap
44	            start_clock = clock64();
45	            while (clock64() - start_clock < kNumOneSecCycles) {}
46	            ptx::trap();
47	        }
48	    }
49	}
