56	template <int kNumSMs, int kNumQPs, int kNumChannelsPerSM, bool kWithNotifyWarps = false>
57	__device__ __forceinline__ std::pair<int, ncclGinResourceSharingMode> get_qp_mode(
58	    const int& sm_idx, const int& channel_in_sm_idx, const bool& is_notify_warp = false) {
59	    constexpr auto kSharingCTA = NCCL_GIN_RESOURCE_SHARING_CTA;
60	    constexpr auto kSharingGrid = kNumSMs == 1 ? NCCL_GIN_RESOURCE_SHARING_CTA : NCCL_GIN_RESOURCE_SHARING_GPU;
61	
62	    // Only one QP
63	    if constexpr (kNumQPs == 1)
64	        return {0, kSharingGrid};
65	
66	    // The notify warp always use 1 SM and 1 QP
67	    if (is_notify_warp)
68	        return {0, kSharingCTA};
69	
70	    // Data channels
71	    constexpr int kQPStartIdx = static_cast<int>(kWithNotifyWarps);
72	    constexpr int kNumAvailableQPs = kNumQPs - kQPStartIdx;
73	    if constexpr (kNumSMs <= kNumAvailableQPs) {
74	        // A single SM uses an entire QP
75	        // e.g., 3 SMs and 10 QPs
76	        // SM 0: 0 3 6 9
77	        // SM 1: 1 4 7
78	        // SM 2: 2 5 8
79	        const int num_qps_in_sm = (kNumAvailableQPs / kNumSMs) + (sm_idx < (kNumAvailableQPs % kNumSMs));
80	        return {kQPStartIdx + sm_idx + (channel_in_sm_idx % num_qps_in_sm) * kNumSMs, kSharingCTA};
81	    } else {
82	        // All SMs share all QPs
83	        const auto global_channel_idx = sm_idx * kNumChannelsPerSM + channel_in_sm_idx;
84	        return {kQPStartIdx + (global_channel_idx % kNumAvailableQPs), kSharingGrid};
85	    }
86	}
