88	template <int kNumRanks, int kNumSMs, int kNumThreads, int64_t kNumTimeoutCycles, int kTag = kDeviceBarrierTag>
89	__forceinline__ __device__ void nvlink_barrier_wo_local_sync(
90	    const handle::NCCLGin& gin,
91	    const layout::WorkspaceLayout& workspace,
92	    const int& rank_idx, const int& sm_idx, const int& thread_idx) {
93	    // This barrier only uses 1 SM
94	    if (kNumSMs > 1 and sm_idx > 0)
95	        return;
96	
97	    // Read the current barrier phase first
98	    const int status = static_cast<int>((*workspace.get_nvl_barrier_counter_ptr()) & 3);
99	    const int phase = status & 1, sign = status >> 1;
100	
101	    EP_STATIC_ASSERT(kNumRanks <= kNumThreads, "Insufficient threads");
102	    if (thread_idx < kNumRanks) {
103	        const auto dst_ptr =
104	            gin.get_sym_ptr<ncclTeamTagLsa>(workspace.get_nvl_barrier_signal_ptr(phase), thread_idx);
105	        ptx::red_add_rel_sys(dst_ptr, sign ? -1 : 1);
106	    }
107	    __syncthreads();
108	
109	    // NOTES: we need `2^64 / 1e6 / 3600 / 24 / 365 = 571000` years to make the counter overflow (1 barrier per us)
110	    // Add the phase counter
111	    if (thread_idx == 0)
112	        atomicAdd(workspace.get_nvl_barrier_counter_ptr(), 1);
113	
114	    // Check timeout
115	    const auto target = sign ? 0 : kNumRanks;
116	    timeout_while<kNumTimeoutCycles>(thread_idx == 0, [=](const bool& is_last_check) {
117	        const auto signal = ptx::ld_acquire_sys<int>(workspace.get_nvl_barrier_signal_ptr(phase));
118	        if (signal == target)
119	            return true;
120	
121	        if (is_last_check) {
122	            printf("DeepEP NVLink barrier timeout, tag: %d, nvl: %d, thread: %d, "
123	                   "status: %d, signal: %d, phase: %d, target: %d, counter: %llu\n",
124	                   kTag, rank_idx, thread_idx, status, signal, phase, target,
125	                   *workspace.get_nvl_barrier_counter_ptr());
126	        }
127	        return false;
128	    });
129	}
